import re
from dataclasses import dataclass, field
from typing import List, Union, Optional


# ===== TOKEN DEFINITIONS =====

@dataclass
class SectionToken:
    name: str # "A", "B", "C", "D", "E".


@dataclass
class QuestionToken:
    number: str # "1", "2".


@dataclass
class SubQuestionToken:
    number: str # "1.1", "1.1.1", "1.2".
    text: str 


@dataclass
class OptionToken:
    label: str
    text: str


@dataclass
class MarkToken:
    value: int 


@dataclass
class TextToken:
    text: str


@dataclass
class InstructionToken:
    text: str # "Answer ALL questions", "Choose ONE of the following".


@dataclass
class FigureToken:
    figure_id: str
    caption: str
    paragraph_contents: List[str] = field(default_factory=list)


@dataclass
class TableCell:
    row_index: int
    column_index: int
    content: str
    is_header: bool = False


@dataclass
class TableToken:
    table_id: str
    row_count: int
    column_count: int
    cells: List[TableCell] = field(default_factory=list)

    def headers(self):
        return [c for c in self.cells if c.is_header]
    
    def rows(self):
        non_headers = [c for c in self.cells if not c.is_header]
        if not non_headers:
            return []
        max_row = max(c.row_index for c in non_headers)
        result = []
        for r in range(max_row + 1):
            row = sorted(
                [c for c in non_headers if c.row_index == r],
                key=lambda c: c.column_index
            )
            if row:
                result.append(row)
        return result


Token = Union[
    SectionToken, 
    QuestionToken, 
    SubQuestionToken, 
    OptionToken, 
    MarkToken, 
    TextToken, 
    InstructionToken,
    FigureToken,
    TableToken
]


# ===== PATTERNS =====

SECTION_RE = re.compile(r'^SECTION\s+([A-Z])\b', re.IGNORECASE) # Matches: "SECTION A", "SECTION B".
QUESTION_RE = re.compile(r'^QUESTION\s+(\d+)\b', re.IGNORECASE) # Matches: "QUESTION 1", "QUESTION 2".
SUBQUESTION_RE = re.compile(r'^(\d+(?:\.\d+)+)\s*(.*)', re.DOTALL) # Matches: "1.1", "1.1.1", "1.2".
OPTION_RE = re.compile(r'^([A-E])\s{1,3}(.+)$') # Matches: "A money", "B capital".
MARK_RE = re.compile(r'^\((\d+)(?:\s*x\s*\d+)?\)$') # Matches: "(2)", "(16)"
TOTAL_MARK_RE = re.compile(r'^[\(\[]\d+[\)\]](?:\s*[\(\[]\d+[\)\]])*$') # Total marks lines.
INSTRUCTION_PATTERNS = [ # DBE instruction patterns common across all subjects.
    re.compile(r'^answer\s+(all|both|\d+)\b', re.IGNORECASE),
    re.compile(r'^choose\s+(one|two|\d+)\b', re.IGNORECASE),
    re.compile(r'^refer\s+to\b', re.IGNORECASE),
    re.compile(r'^use\s+the\s+(diagram|table|graph|source|extract|figure)\b', re.IGNORECASE),
    re.compile(r'^study\s+the\s+(diagram|table|graph|source|extract|figure)\b', re.IGNORECASE),
    re.compile(r'^read\s+the\s+(passage|extract|text)\b', re.IGNORECASE),
    re.compile(r'^\d+\s+marks\s*[-–]\s*\d+\s+minutes$', re.IGNORECASE),
]
BOILERPLATE = { # Document boilerplate text to skip entirely.
    "copyright reserved",
    "please turn over",
    "turn over",
    "end of question paper",
    "keep this page blank",
    "end",
    "nsc",
    "nss",
    "dbe",
}
SKIP_ROLES = { "pageHeader", "pageFooter", "pageNumber" } # Azure roles to skip


# ===== HELPERS =====

def is_boilerplate(text: str):
    lower = text.lower().strip()

    if lower in BOILERPLATE:
        return True

    # Page headers like "Economics/P1", "Mathematics/P2", "DBE/November 2021".
    if re.match(r'^[a-z\s]+/p\d+$', lower):
        return True
    if re.match(r'^dbe/\w+\s+\d{4}$', lower):
        return True
    
    # Standalone numbers (page numbers that slipped through).
    if re.match(r'^\d+$', text.strip()):
        return True
    
    return False


def is_instruction(text: str):
    for pattern in INSTRUCTION_PATTERNS:
        if pattern.match(text):
            return True
    return False


def is_option(text: str):
    """
    Guards against misclassifying subquestion text that starts with a letter.
    Real options in DBE papers are short and self contained.
    'A money' is an option.
    'A cash incentive that aims to provide...' is subquestion text.
    Use two signals: length and whether the letter is followed by
    a short burst of text with no subquestion number pattern inside it.
    """
    m = OPTION_RE.match(text)
    if not m:
        return False
    
    option_text = m.group(2).strip()

    # If the option text itself contains a subquestion number it is not an option
    if SUBQUESTION_RE.match(option_text):
        return False
        
    # DBE options are rarely longer than 80 characters.
    # "C Growth, Employment and Redistribution Programme." is 51 chars.
    # Anything over 80 is almost certainly instruction or subquestion text.
    if len(text) > 80:
        return False
    return True


def build_figure_lookup(figures):
    """
    Returns a dict mapping paragraph span offsets to FigureToken.
    Each figure claims all paragraph offsets listed in its elements/spans
    so it can skip those paragraphs when theyby come up in normal flow
    and instead showcase the FigureToken once at the right postion.
    Figure is showcased at the offset of its first paragraph element.
    """
    lookup = {} # offset -> FigureToken (only set for the first paragraph of the figure).
    figure_offsets = set() #  all offsets that belong to any figure.

    if not figures:
        return lookup, figure_offsets
    
    for fig in figures:
        fig_id = fig.id if hasattr(fig, "id") else fig.get("id", "unknown")

        raw_caption = fig.caption if hasattr(fig, "caption") else fig.get("caption", None)
        if raw_caption is None:
            caption_text = ""
        elif hasattr(raw_caption, "content"):
            caption_text = raw_caption.content
        else:
            caption_text = raw_caption.get("content", "")

        
        # Collect all span offsets this figure owns.
        spans = fig.spans if hasattr(fig, "spans") else fig.get("spans", [])
        fig_spans_offsets = set()
        first_offset = None
        for span in spans:
            offset = span.offset if hasattr(span, "offset") else span.get("offset")
            if offset is not None:
                fig_spans_offsets.add(offset)
                if first_offset is None or offset < first_offset:
                    first_offset = offset

        if first_offset is None:
            continue

        figure_offsets.update(fig_spans_offsets)
        lookup[first_offset] = FigureToken(
            figure_id=fig_id,
            caption=caption_text,
            paragraph_contents=[]
        )
    
    return lookup, figure_offsets


def build_table_lookup(tables):
    """
    Returns a dict maping first span offset -> TableToken,
    and a set of all offsets owned by any table
    """

    lookup = {}
    table_offsets = set()

    if not tables:
        return lookup, table_offsets

    for idx, table in enumerate(tables):
        table_id = f"table_{idx}"

        row_count = table.rowCount if hasattr(table, "rowCount") else table.get("rowCount", 0)
        column_count = table.columnCount if hasattr(table, "columnCount") else table.get("columnCount", 0)

        spans = table.spans if hasattr(table, "spans") else table.get("spans", [])
        first_offset = None
        for span in spans:
            offset = span.offset if hasattr(span, "offset") else span.get("offset")
            if offset is not None:
                table_offsets.add(offset)
                if first_offset is None or offset < first_offset:
                    first_offset = offset

        if first_offset is None:
            continue

        cells_raw = table.cells if hasattr(table, "cells") else table.get("cells", [])
        cells = []
        for cell in cells_raw:
            kind = cell.kind if hasattr(cell, "kind") else cell.get("kind", "")
            row_index = cell.rowIndex if hasattr(cell, "rowIndex") else cell.get("rowIndex", 0)
            col_index = cell.columnIndex if hasattr(cell, "columnIndex") else cell.get("columnIndex", 0)
            content = cell.content if hasattr(cell, "content") else cell.get("content", "")
            is_header = kind == "columnHeader"

            # Add all cell span offsets to the owned set
            cell_spans = cell.spans if hasattr(cell, "spans") else cell.get("spans", [])
            for cs in cell_spans:
                cs_offset = cs.offset if hasattr(cs, "offset") else cs.get("offset")
                if cs_offset is not None:
                    table_offsets.add(cs_offset)

            cells.append(TableCell(
                row_index=row_index,
                column_index=col_index,
                content=content,
                is_header=is_header
            ))

        lookup[first_offset] = TableToken(
            table_id=table_id,
            row_count=row_count,
            column_count=column_count,
            cells=cells
        )

    return lookup, table_offsets


# ===== CLASSIFIER =====

def classify_paragraph(content: str, role: Optional[str] = None):
    """
    Takes a single paragraph from the OCR and returns token/s.
    A paragraph can contain a subquestion number and its text, 
    so it can return multiple tokens from one paragraph.
    """

    text = content.strip()

    if not text:
        return []

    # Skip headers, footers, aand page numbers.
    if role in SKIP_ROLES:
        return []
    
    if is_boilerplate(text):
        return []
    
    # ----- Section -----
    m = SECTION_RE.match(text)
    if m: 
        return [SectionToken(name=m.group(1).upper())]

    # ----- Question -----
    m = QUESTION_RE.match(text)
    if m: 
        return [QuestionToken(number=m.group(1))]

    # ----- Total Mark -----
    # Skip total mark lines like "(8 x 2) (16)"
    if TOTAL_MARK_RE.match(text):
        return []

    # ----- Single Mark -----
    m = MARK_RE.match(text)
    if m: 
        return [MarkToken(value=int(m.group(1)))]

    # ----- Subquestion - comes before option check -----
    m = SUBQUESTION_RE.match(text)
    if m:
        number = m.group(1)
        remainder = m.group(2).strip()
        return [SubQuestionToken(number=number, text=remainder)]
        
    # ----- Instruction -----
    if is_instruction(text): return [InstructionToken(text=text)]
    
    # ----- Option -----
    if is_option(text):
        m = OPTION_RE.match(text)
        if m is not None:
            return [OptionToken(label=m.group(1), text=m.group(2).strip())]
    
    # Everything else.
    return [TextToken(text=text)]


def classify_paragraphs(paragraphs, figures=None, tables=None):
    figure_lookup, figure_offsets = build_figure_lookup(figures or [])
    table_lookup, table_offsets = build_table_lookup(tables or [])

    tokens: List[Token] = []
    showcased_figures = set()
    showcased_tables = set()

    for para in paragraphs:
        content = para.content if hasattr(para, "content") else para.get("content", "")
        role = para.role if hasattr(para, "role") else para.get("role", None)

        # Get the span offset of this paragraph to chec against ownership.
        para_spans = para.spans if hasattr(para, "spans") else para.get("spans", [])
        para_offset = None
        if para_spans:
            first_span = para_spans[0]
            para_offset = first_span.offset if hasattr(first_span, "offset") else first_span.get("offset")

        # If this offset is the start of a figure, showcase the FigureToken once.
        if para_offset is not None and para_offset in figure_lookup:
            fig_token = figure_lookup[para_offset]
            if fig_token.figure_id not in showcased_figures:
                tokens.append(fig_token)
                showcased_figures.add(fig_token.figure_id)
            continue

        # If this paragraph belongs to figure (its not the first), skip it.
        if para_offset is not None and para_offset in figure_offsets:
            continue

        # Showcase TableToken once at its first paragraph
        if para_offset is not None and para_offset in table_lookup:
            tbl_token = table_lookup[para_offset]
            if tbl_token.table_id not in showcased_tables:
                tokens.append(tbl_token)
                showcased_tables.add(tbl_token.table_id)
            continue

        if para_offset is not None and para_offset in table_offsets:
            continue

        new_tokens = classify_paragraph(content, role)
        tokens.extend(new_tokens)

    return tokens


